INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('9ddcdb3b-e6e5-4bb5-b09d-37f7790b8765', 'aleph-occrp', 'Aleph (OCCRP)', NULL, 'Verification & Investigations', '["Verification & Investigations"]', 'Aleph (OCCRP) Investigative database for searching public records, leaks, and corporate ownership data worldwide. Aleph is a massive, open-access 58 data platform created by the Organized Crime and Corruption Reporting Project (OCCRP). It acts as a "global archive of research material for investigative reporting," indexing public records, leaks, and databases to help trace assets and corporate ownership worldwide. The OCCRP is a non-profit media organization dedicated to exposing crime. Unlike commercial compliance databases, Aleph is free for journalists and activists 59, democratizing access to financial intelligence.', 'Follow-the-money database.', 0, 4, 1, '2026-05-14 23:35:39.473313+02', '2026-05-14 23:41:54.971169+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('e0eb4051-9ef2-4dfc-8e36-164d48500e07', 'apify', 'Apify', 'https://chatgpt.com/atlas/', 'AI Agents & Automated Workflows', '["AI Agents & Automated Workflows"]', '', NULL, 4, 3, 3, '2026-05-14 23:35:39.474369+02', '2026-05-14 23:41:54.972114+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('ec024b9f-535d-4066-8034-9d0a4dc8087c', 'autogen', 'AutoGen', 'https://github.com/microsoft/autogen', 'AI Agents & Automated Workflows', '["AI Agents & Automated Workflows"]', '', NULL, 1, 7, 2, '2026-05-14 23:35:39.475375+02', '2026-05-14 23:41:54.972869+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('fb788719-a995-48e1-a681-1aed493ef3dc', 'bitwarden', 'Bitwarden', 'https://www.torproject.org', 'Security Challenges', '["Security Challenges"]', 'Open-source password manager with end-to-end encryption. Bitwarden is a popular open-source password manager that securely stores all your passwords in an encrypted vault. It helps generate strong, unique passwords for each account and auto-fills them when needed, so you don’t have to remember or reuse passwords. All data stored in Bitwarden is end-to-end encrypted (zero-knowledge), meaning even Bitwarden’s servers can’t read your passwords. The service has undergone independent security audits in 2023 and to ensure its integrity. Journalists often manage numerous online accounts (email, social media, cloud services, databases). A password manager is vital for protecting these accounts from hacking. Using strong, unique passwords for every account is one of the simplest yet most effective security steps', 'Secure password storage and account protection.', 0, 2, 1, '2026-05-14 23:35:39.477043+02', '2026-05-14 23:41:54.97439+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('27afec37-0aad-47d1-8f6e-406cf848312b', 'buffer-ai-assistant', 'Buffer AI Assistant', 'https://buffer.com', 'Audio, Video & Social', '["Audio, Video & Social"]', 'Social media scheduling and caption-generation tool integrated into Buffer. Buffer is a social media management platform, and its AI Assistant is integrated to help draft, repurpose, and schedule content across platforms. The AI helps generate post ideas, rewrite content for different networks (e.g., shorten for X, expand for LinkedIn), and summarize long articles into threads. It uses OpenAI''s API but is tuned for social media best practices.', 'To help newsrooms plan, adapt, and publish content across multiple', 3, 2, 3, '2026-05-14 23:35:39.47791+02', '2026-05-14 23:41:54.975149+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('6d11aa7f-6042-4b3b-8961-c0e33611516c', 'chatgpt-atlas', 'ChatGPT Atlas', NULL, 'AI Agents & Automated Workflows', '["AI Agents & Automated Workflows"]', '', NULL, 4, 2, 4, '2026-05-14 23:35:39.48555+02', '2026-05-14 23:41:54.976607+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('aed4e38d-08f7-4782-a474-baf45ed22634', 'chatgpt-team-plan', 'ChatGPT Team Plan', NULL, 'Writing & Analysis', '["Writing & Analysis"]', 'Collaborative version of ChatGPT offering shared workspaces and enhanced data controls. The ChatGPT Team plan is the professional tier of the world''s most famous chatbot. It bridges the gap between the individual "Plus" user and the "Enterprise" tier, offering a collaborative workspace with data privacy guarantees. The Team plan is their answer to corporate security concerns. There have been useful studies on benchmarking the Performance of LLMs in processing of the Ukrainian language 72.', 'Data Analysis and Excel formulas.', 5, 2, 8, '2026-05-14 23:35:39.486754+02', '2026-05-14 23:41:54.977227+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('6ed6a9ec-6f70-42fb-be81-a5a9ad01dc36', 'cursor', 'Cursor', 'https://cursor.sh', 'Building Your Own Tools', '["Building Your Own Tools"]', 'AI-first code editor that allows users to build software using natural language prompts. Cursor is a desktop application that lets you build and modify digital tools by talking to the computer in natural language. Instead of writing complex code line by line, you describe what you want the tool to do, and Cursor generates or edits the technical parts for you. Cursor “reads” all the files in your project, so when you ask it to make a change, it understands the full context — not just one screen or document. This makes it possible to build or adjust tools gradually, even if you don’t fully understand how they work under the hood. Cursor can work with different AI systems (such as ChatGPT or Claude) and can also be set up to run entirely on your own computer, which is important for sensitive journalism.', 'A professional-grade tool for building custom newsroom software', 5, 4, 2, '2026-05-14 23:35:39.490063+02', '2026-05-14 23:41:54.978526+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('636689bf-6b3d-49f1-b8c5-b437b75c3cd0', 'custom-gpts', 'Custom GPTs', 'https://www.journalismai.info/programmes/innovation/innovation-challenge-2024', 'Building Your Own Tools', '["Building Your Own Tools"]', '', NULL, 4, 2, 6, '2026-05-14 23:35:39.490693+02', '2026-05-14 23:41:54.981664+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('78af5cb8-9f2d-4908-8a52-59eeb7286e97', 'dangerzone-security-challenges', 'Dangerzone', NULL, 'Security Challenges', '["Security Challenges"]', 'Tool for safely opening and sanitising documents from untrusted sources. Dangerzone is a security tool designed specifically for journalists handling untrusted documents from anonymous sources. It converts potentially malicious PDFs, Word files, or images into safe, inert PDFs by opening them in a sandboxed environment and reconstructing them as images. Developed by Micah Lee at the Freedom of the Press Foundation, Dangerzone assumes all leaked documents are hostile until proven otherwise.', 'Safe handling of leaks and anonymous submissions.', 0, 3, 0, '2026-05-14 23:35:39.491188+02', '2026-05-14 23:41:54.982774+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('88003d77-c360-4560-a240-00294933aa11', 'dangerzone', 'Dangerzone', NULL, 'Verification & Investigations', '["Verification & Investigations"]', 'Local document sanitisation tool that converts untrusted files into safe, non-executable PDFs. Dangerzone is a specialized security tool that sanitizes potentially malicious documents. It takes untrusted PDFs, office documents, or images and converts them into safe, inert PDFs. Dangerzone works by creating a sandbox (a secure, isolated environment) where you can open the suspicious file and convert it 65 into raw pixel data (images), and then reconstruct a new PDF from those images. Developed by Micah Lee at the Freedom of the Press Foundation, Dangerzone is explicitly designed for journalists handling leaks from anonymous sources.', 'Safe handling of leaks and untrusted documents.', 0, 3, 0, '2026-05-14 23:35:39.49188+02', '2026-05-14 23:41:54.983267+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('32f6adea-0fd4-4462-808e-331ec5888141', 'deepl-pro', 'DeepL Pro', 'https://www.deepl.com/pro', 'Transcription & Translation', '["Transcription & Translation"]', 'High-accuracy machine translation and writing refinement tool designed for professional and editorial use. DeepL Pro is widely considered the gold standard for AI-driven machine translation 30, consistently outperforming competitors like Google Translate in linguistic nuance and grammatical accuracy 31. It offers a suite of tools including a web translator, document translation (preserving formatting for.docx,.pptx,.pdf), and an API for integration into other software. The "DeepL Write" feature acts as an AI copyeditor 32, refining style and tone in addition to translating, which aids in producing professional-grade communications in non-native languages. Based in Cologne, Germany, DeepL adheres to strict European Union data protection (GDPR) standards.33 This provenance is significant for users concerned with data sovereignty and US- based surveillance or data mining.', 'High-nuance translation for wire reports.', 5, 1, 4, '2026-05-14 23:35:39.492481+02', '2026-05-14 23:41:54.984815+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('7e800467-da84-48db-ba1a-6926dcb62a3b', 'descript', 'Descript', NULL, 'Audio, Video & Social', '["Audio, Video & Social"]', 'Audio and video editor that allows users to edit media by editing text transcripts. Descript reimagines video and audio editing by treating it like a word processor. Instead of cutting waveforms on a timeline, users edit the transcript text, and the AV is cut automatically. Descript pioneered the text-based editing paradigm. It lowers the barrier to entry for podcast and video production significantly, democratizing high-quality editing. Incredible speed for dialogue editing. Text-based workflow is intuitive. However, it can be buggy/resource-heavy on large projects, and the "text-first" approach is less precise for frame-perfect visual cuts than Premiere Pro. ● The tool’s purpose: To make audio and video editing faster and more accessible by allowing journalists to edit recordings through text rather than complex timelines. ● Relevance to journalism: Ideal for podcasts, interviews, and explainer videos, Descript enables reporters and editors to produce polished audio and video without specialist editing skills, while retaining editorial control over what is cut and kept.', NULL, 5, 3, 4, '2026-05-14 23:35:39.49299+02', '2026-05-14 23:41:54.985287+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('9dfedaee-2d73-4811-982c-31f5b914b1c7', 'gemini', 'Gemini', NULL, 'Writing & Analysis', '["Writing & Analysis"]', 'Google’s large language model integrated into Docs, Drive, and multimedia analysis tools. Gemini is Google’s multimodal large language model, deeply integrated into Google Docs, Drive, Gmail, and YouTube. Its primary strength lies in working directly with content already stored in the Google ecosystem, allowing journalists to summarise long documents 79, analyse emails, or extract timelines without exporting files. However, this tight integration also creates dependency on Google’s infrastructure, making it unsuitable for sensitive investigations or source material.', 'To help users quickly analyse, summarise, and work with documents,', 5, 2, 7, '2026-05-14 23:35:39.516647+02', '2026-05-14 23:41:54.986922+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('bf13f239-804c-4e75-b23b-c4d33a7f37ca', 'happyscribe', 'HappyScribe', 'https://www.happyscribe.com', 'Transcription & Translation', '["Transcription & Translation"]', 'Transcription and subtitle platform combining AI output with human editing workflows for publication-ready text. HappyScribe operates as a hybrid transcription and subtitling platform 27 that bridges the gap between AI automation and human precision. Its defining feature is the integrated "Human Review" service and a highly sophisticated interactive editor designed specifically for subtitling workflows. It supports over 120 languages and dialects 28, catering to a global user base that requires nuance often missed by purely algorithmic approaches. The platform’s interactive editor is its standout technical achievement. It allows users to visually sync text with audio waveforms, adjust timing for subtitles, and correct speaker labels dynamically. This makes it superior for post-production video work where timing precision is paramount. HappyScribe is a European company that has carved a niche by focusing on the workflow of transcription rather than just the raw AI output.', 'Video subtitles and translation for social distribution.', 6, 2, 6, '2026-05-14 23:35:39.523825+02', '2026-05-14 23:41:54.988715+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('d86b580b-1fc7-4d10-9420-a6c0ce707b70', 'languagetool', 'LanguageTool', 'https://pandas.pydata.org', 'Writing & Analysis', '["Writing & Analysis"]', 'Grammar and style checker that can be run locally or self-hosted for privacy. LanguageTool is the sovereign alternative to Grammarly. It is an open-source proofreading software that checks for grammar, style, and spelling errors in over 20 languages. Crucially, it can be hosted on a local server, ensuring no text leaves the organization.', 'Privacy-safe language correction.', 0, 2, 0, '2026-05-14 23:35:39.526912+02', '2026-05-14 23:41:54.989588+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('df992ac3-71f8-4637-af1f-3bf7cc57ae20', 'midjourney', 'Midjourney', NULL, 'Audio, Video & Social', '["Audio, Video & Social"]', 'AI image generation tool accessed via Discord, focused on high-quality visual illustration. Midjourney is widely regarded as the most artistically capable AI image generator. Accessible primarily via Discord, it generates high-fidelity, creative, and photorealistic images from text prompts. ● The tool''s purpose: Conceptual illustration. ● Relevance to journalism: Creating visuals for abstract topics like "inflation," "cyberwar," or "corruption" when all the stock photos you find are boring.', NULL, 5, 6, 5, '2026-05-14 23:35:39.527821+02', '2026-05-14 23:41:54.990035+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('9edb659b-7d54-4265-abbc-befbd2d4d427', 'n8n', 'n8n', 'https://n8n.io', 'AI Agents & Automated Workflows', '["AI Agents & Automated Workflows"]', '', NULL, 1, 7, 1, '2026-05-14 23:35:39.528478+02', '2026-05-14 23:41:54.990766+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('a4992412-c92c-4112-ad57-42c65cf5f6c8', 'narakeet', 'Narakeet', NULL, 'Transcription & Translation', '["Transcription & Translation"]', 'Text-to-speech and slide-to-video tool for creating narrated audio and video content from documents. Narakeet is a specialized tool designed to convert text into spoken audio and to transform PowerPoint slides into narrated videos automatically. It streamlines the creation of voiceovers for educational content, YouTube videos, and internal training materials without the need for recording equipment. Narakeet supports 100 languages and offers 800 voices.', 'Specialized TTS for Georgian and Armenian.', 4, 1, 3, '2026-05-14 23:35:39.528904+02', '2026-05-14 23:41:54.991492+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('e83a7317-5d67-4b06-be2f-55d4ce60271e', 'ollama', 'Ollama', 'https://ollama.com', 'Writing & Analysis', '["Writing & Analysis"]', 'Local LLM runtime for running open-weight language models on personal hardware. Ollama is a lightweight runtime that makes it easy to download, manage, and run AI open- weight large language models locally on a personal computer. With a single terminal command, users can run models such as Llama 3, Mistral, Gemma, or DeepSeek entirely offline, without sending prompts or data to external servers. Ollama abstracts away much of the complexity of model hosting (weights, inference servers, model switching), making local AI experimentation accessible to non-specialists.', 'To run open-weight large language models directly on a personal', 0, 6, 0, '2026-05-14 23:35:39.530448+02', '2026-05-14 23:41:54.994099+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('7d208e6e-8063-4192-b9ab-72dfbfa5495e', 'openai-whisper', 'OpenAI Whisper', 'https://www.narakeet.com', 'Transcription & Translation', '["Transcription & Translation"]', 'Open-source automatic speech transcription model that can be run locally for security. Developed by OpenAI and released as open-source 36 Whisper represents a rare moment where a frontier AI lab released a state-of-the-art model weights-and-all. While OpenAI is a corporate entity, the open sourcing of Whisper empowers the sovereign individual. . Trained on 680,000 hours of multilingual, multitask supervised data, Whisper excels at robustness against accents, background noise, and technical jargon. Because it runs via Python or command-line interface (CLI) locally,37 there are no file size limits or upload caps— only the limitations of the user''s hardware.', 'The gold standard for secure, high-accuracy transcription.', 0, 8, 0, '2026-05-14 23:35:39.531046+02', '2026-05-14 23:41:54.994742+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('a2e8546e-78b9-4387-8014-c927e52aa40d', 'openrefine', 'OpenRefine', 'https://gemini.google.com', 'Writing & Analysis', '["Writing & Analysis"]', 'Open-source tool for cleaning, clustering, and transforming messy datasets. page.html#:~:text=You%20can%20now%20see%20Gemini,in%20the%20Gemini%20side%20panel OpenRefine is a free tool that helps journalists work with messy or poorly formatted data. It is especially useful for cleaning spreadsheets, fixing inconsistencies, and preparing data so it can be properly analysed. It is widely used in data journalism because many official datasets are incomplete, inconsistent, or badly structured. Essential for cleaning government datasets where "Chisinau", "Chișinău", and "Kishinev" need to be merged into one entry. The tool looks similar to a spreadsheet, but it is much more powerful. Originally developed with Google’s support and later released to the public, OpenRefine is now maintained by a global community and is considered a standard tool for cleaning and preparing data before reporting.', 'Cleaning messy data.', 0, 6, 0, '2026-05-14 23:35:39.531459+02', '2026-05-14 23:41:54.996097+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('44c5bfc1-a669-437b-9e7e-1b5a2baad97b', 'opusclip', 'OpusClip', 'https://www.descript.com', 'Audio, Video & Social', '["Audio, Video & Social"]', 'AI tool that extracts short, shareable video clips from long-form content. OpusClip is a specialized generative AI tool that repurposes long-form video (podcasts, webinars) into viral-style short clips (Shorts, Reels, TikToks). It uses NLP to analyze the video transcript and identify "hooks" or viral moments. It automatically reframes horizontal video to vertical (9:16), keeping the speaker in focus (active speaker detection). OpusClip targets the "creator economy" need for volume. It automates the tedious task of finding highlights, allowing creators to scale content output without a dedicated editing team.', 'Viral short creation.', 4, 1, 5, '2026-05-14 23:35:39.532506+02', '2026-05-14 23:41:54.997552+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('b58f3205-d013-49b1-b230-b3d78488d461', 'veracrypt', 'VeraCrypt', 'https://www.veracrypt.fr', 'Security Challenges', '["Security Challenges"]', 'Open-source disk encryption software for protecting files and entire drives. VeraCrypt is the gold standard for open-source disk encryption. It allows users to create encrypted file containers or encrypt entire hard drives/partitions, rendering data inaccessible without the key. Maintained by IDRIX (France), VeraCrypt is audited and trusted by the security community. In an era of border checks and device seizures, it is the primary defense for data at rest.', 'To protect files and entire devices by encrypting them so that data cannot', 0, 6, 0, '2026-05-14 23:35:39.539119+02', '2026-05-14 23:41:55.002499+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('92865dc0-1d40-4929-b8b0-1ea92c5cbaa2', 'perplexity', 'Perplexity', 'https://chat.openai.com', 'Writing & Analysis', '["Writing & Analysis"]', 'AI-powered search engine that synthesises answers with citations from live web sources. Perplexity is an engine that challenges the traditional Google Search paradigm 74. Instead of a ai/#:~:text=Perplexity%20Decoded%3A%20Lessons%20from%20the,and%20synthesize%20information %20through%20AI list of links, it uses LLMs (ChatGPT, Claude) to read search results and synthesize a direct answer with citations. Perplexity was created by people who previously worked at major tech companies like OpenAI and Google, with the goal of making online search less cluttered and more useful. However, it has also been criticised for collecting 75 information from websites in ways that some publishers do not agree with, which has caused tension with parts of the media industry. But they are not the only LLM doing this 76. ● The tool''s purpose: The "Journalistic" Search Engine. ● Relevance to journalism: Provides citations for every claim. Excellent for background research on complex geopolitical topics.', NULL, 3, 1, 4, '2026-05-14 23:35:39.533961+02', '2026-05-14 23:41:54.99822+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('67b19cee-6923-434a-86cc-e5a780f73063', 'protonmail', 'ProtonMail', 'https://dangerzone.rocks', 'Security Challenges', '["Security Challenges"]', 'Encrypted email service designed for secure communications. ProtonMail is an encrypted email service designed with privacy in mind. Based in Switzerland, it provides end-to-end encryption (E2EE) for emails between ProtonMail users, meaning the messages are encrypted on the sender’s device and can only be decrypted by the recipient. Even when emailing non-ProtonMail contacts, ProtonMail allows you to send a password- protected encrypted message that the recipient can decrypt with a shared password. The service is open source and has a user-friendly interface similar to mainstream email, making secure email accessible without special technical knowledge.', 'Secure email for sensitive journalistic communications.', 2, 3, 2, '2026-05-14 23:35:39.534846+02', '2026-05-14 23:41:54.998641+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('fd801f94-38fc-4d4f-bc30-3f4b0bb26566', 'replit', 'Replit', NULL, 'Building Your Own Tools', '["Building Your Own Tools"]', 'Browser-based coding platform for rapid prototyping and deployment of small applications. Replit is a collaborative, browser-based integrated development environment (IDE). It allows users to write, run, and deploy code instantly from any device without setup. Founded by Amjad Masad, Replit aims to democratize coding. It is particularly popular for rapid prototyping and education.', 'Zero-setup web app builder.', 5, 2, 6, '2026-05-14 23:35:39.535491+02', '2026-05-14 23:41:54.998935+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('de749099-6152-4439-90af-6b75680b1280', 'runway', 'Runway', 'https://runwayml.com', 'Audio, Video & Social', '["Audio, Video & Social"]', 'AI-powered video generation and editing platform for text-to-video and visual effects. Runway is a research company pioneering AI video generation. Their Gen-2 and Gen-3 Alpha models allow for text-to-video, video-to-video, and image-to-video creation, effectively acting as an AI film studio. Runway created the original Stable Diffusion model. They are a core innovator in the space, often releasing features months before Adobe or OpenAI. They focus on professional filmmakers, not just casual users.', 'B-roll generation.', 7, 5, 5, '2026-05-14 23:35:39.536023+02', '2026-05-14 23:41:54.999339+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('b87b8933-6d0d-497d-af8c-1c6d84977bff', 'tabula', 'Tabula', 'https://tabula.technology', 'Writing & Analysis', '["Writing & Analysis"]', 'Tool for extracting tables from PDF documents into CSV or Excel formats. Tabula is a specialized tool designed to solve one specific, painful problem: extracting data tables from PDF files into CSV or Excel formats. It is widely used by investigative journalists to liberate data locked in government reports. Tabula runs locally in a web browser. Users upload a PDF, draw a box around the table, and Tabula attempts to parse the layout and extract the text into cells.', 'Liberating data from PDFs.', 0, 4, 0, '2026-05-14 23:35:39.536745+02', '2026-05-14 23:41:54.999606+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('fd4128e3-d6a9-4d2a-a51b-849b14fb970e', 'turboscribe', 'TurboScribe', 'https://turboscribe.ai', 'Transcription & Translation', '["Transcription & Translation"]', 'Cloud-based transcription tool built on Whisper that allows bulk uploads and fast, multilingual transcription. The core engine of TurboScribe is built upon OpenAI''s Whisper technology, widely regarded as the industry standard for open-source speech-to-text accuracy. However, TurboScribe wraps this raw model in a user-friendly, GPU-accelerated infrastructure. This allows for features such as automatic speaker recognition, built-in translation to over 134 languages 25, and the ability to upload 50 files simultaneously for bulk processing. TurboScribe was created by Leif, an independent developer who focused on making the power of the Whisper model accessible and less technical. The tool is not interested in harvesting your data, however, it does run in the cloud (rather than securely on your machine) so you do need to have trust in their encryption standards and retention policies.', 'Handling massive archives for low-budget newsrooms.', 3, 1, 5, '2026-05-14 23:35:39.538538+02', '2026-05-14 23:41:55.000317+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('b899741a-cf73-4e58-b66e-0f0ce8d3a002', 'adobe-firefly', 'Adobe Firefly', 'https://www.midjourney.com', 'Audio, Video & Social', '["Audio, Video & Social"]', 'Commercially safe generative AI integrated into Adobe’s creative tools. Adobe Firefly is integrated into Photoshop and Illustrator and offers image generation that is safe for commercial use, trained on Adobe Stock images rather than scraped internet data 91. Firefly powers the "Generative Fill" tool in Photoshop, allowing users to extend images or add/remove objects with perfect lighting matching. In this context, “Generative Fill” means using generative AI to create new pixels that complete or modify an image based on a user’s intent or description. You are not just cloning or patching an image like you would with traditional Photoshop tools. It analyses the existing image and produce new content that matches the surrounding lighting, perspective and style wherever you make a selection. Its "Structure Reference" allows users to upload a sketch and generate an image that matches the layout. It now includes a video model.', '"Safe" generative fill.', 6, 2, 4, '2026-05-14 23:35:39.417342+02', '2026-05-14 23:41:54.962012+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('6e87301a-3dde-4356-83cb-456be31c4716', 'bellingcat-online-investigation-toolkit', 'Bellingcat Online Investigation Toolkit', 'https://bellingcat.gitbook.io/toolkit', 'Verification & Investigations', '["Verification & Investigations"]', 'Bellingcat Online Investigation Toolkit Curated collection of open-source tools and methods for digital investigations. The Bellingcat Toolkit is not a single piece of software but a curated, dynamic repository of open-source tools maintained by the world''s premier citizen investigation collective. 55 It serves as the definitive map for the OSINT landscape, organizing tools by function: geolocation, data verification, archiving, and transport analysis. The toolkit includes guides and links 56 to satellite imagery services, shadow analysis tools and social media scrapers. Bellingcat has revolutionized journalism by proving that open-source data can solve war crimes and expose state secrets. Their toolkit is the crystallization of this methodology. Using their toolkit aligns the researcher with a methodology of transparency and verifiability. It is a community-driven resource, democratizing access to intelligence capabilities previously reserved for state agencies.', 'Methodology and geolocation tools.', 0, 9, 0, '2026-05-14 23:35:39.476247+02', '2026-05-14 23:41:54.973475+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('6ca7b2c7-5179-4be5-8f7d-316bbf592311', 'changedetectionio', 'Changedetection.io', 'https://github.com/neo4j/neo4j', 'Verification & Investigations', '["Verification & Investigations"]', 'Self-hosted, open-source website change monitoring tool offering privacy and unlimited checks. Changedetection.io lets you keep an eye on websites and get alerts 63 when something changes. For example, when a government page is quietly updated, a report is removed, or wording is altered after public criticism. Unlike commercial services, this tool runs under your own control instead of on someone else’s platform. That means no company can see which websites you are monitoring, and there are no limits on how many pages you track or how often you check them. Because it does not rely on a third-party service, there are no monthly fees and no risk that your monitoring activity is logged or shared. It is especially useful for journalists who need to watch sensitive or politically important websites without drawing attention. It gives you a way to monitor website changes quietly, privately, and for free, without handing that information to another company.', 'Private, independent monitoring of website changes.', 0, 4, 0, '2026-05-14 23:35:39.478536+02', '2026-05-14 23:41:54.975678+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('7354cd2d-58a2-4320-b0e6-372be6027a35', 'claude', 'Claude', 'https://www.anthropic.com/claude', 'Writing & Analysis', '["Writing & Analysis"]', 'Large language models optimized for long documents, reasoning and analytical writing tasks. Claude Opus 4.5 (released November 2025 68) is positioned as the world''s premier model for complex reasoning, coding, and agentic tasks. It is the flagship model from Anthropic, designed to outperform competitors in deep research and extended cognitive tasks. Anthropic was founded by former OpenAI safety researchers. Their "Constitutional AI" approach prioritizes safety and steerability 69. For investigators, this means Claude is often less prone to sycophancy 70 (agreeing with the user falsely) and better at nuanced, neutral analysis than ChatGPT.', 'The "Editor" and "Coder."', 5, 4, 3, '2026-05-14 23:35:39.487469+02', '2026-05-14 23:41:54.977689+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('338bfc0b-22e0-4de6-8eec-2ed9c1182306', 'notebooklm', 'NotebookLM', 'https://notebooklm.google', 'Verification & Investigations', '["Verification & Investigations"]', 'AI-powered research and synthesis tool grounded in user-provided source documents. NotebookLM is a research assistant designed to work only from materials you upload, such as PDFs, transcripts, reports, notes, or web articles. Unlike general chatbots, it does not answer from the open internet by default; it reasons strictly within the provided sources and cites them directly. This makes it particularly useful for sense-making, summarisation, and comparison across large document collections. NotebookLM excels at helping users interrogate complex material: asking questions across documents, generating summaries, extracting themes, and explaining contradictions while pointing back to the original text. It is not a writing or publishing tool; it is a thinking and reading companion. As part of Google’s ecosystem, it prioritises ease of use and rapid onboarding, but uploaded materials are processed on Google servers.', 'Source-grounded research, synthesis, and sense-making.', 0, 1, 6, '2026-05-14 23:35:39.529968+02', '2026-05-14 23:41:54.993507+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('f75ded20-8c38-47e0-8d8d-87dcf00c1121', 'zapier-ai', 'Zapier AI', 'https://zapier.com', 'AI Agents & Automated Workflows', '["AI Agents & Automated Workflows"]', '', NULL, 5, 2, 2, '2026-05-14 23:35:39.541174+02', '2026-05-14 23:41:55.003464+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('071dfc60-4820-4998-beb2-bec7223bc7d3', 'elevenlabs', 'ElevenLabs', 'https://elevenlabs.io', 'Audio, Video & Social', '["Audio, Video & Social"]', 'AI voice synthesis and dubbing platform for realistic text-to-speech and multilingual audio. ElevenLabs is the market leader in AI voice synthesis. It creates hyper-realistic text-to- speech (TTS) and offers voice cloning capabilities that are virtually indistinguishable from human speech. The platform offers "Voice Design" to create custom voices and "Voice Cloning" to replicate a specific person''s voice from a short sample. Its "Dubbing Studio" automatically translates video audio into other languages while preserving the original speaker''s voice characteristics and syncing the lips (in some modes). ElevenLabs has set the benchmark for quality but also sparked ethical debates regarding deepfakes. Their "Voice Isolator" and safety measures attempt to mitigate misuse, but the tool remains the primary engine for both high-end content creation and unauthorized voice cloning. The languages offered depends on the model of ElevenLabs that you are using 86. For Multilingual v2 you have 29 languages. These include Arabic, Bulgarian, Chinese (Mandarin), Croatian, Czech, Danish, Dutch, English, Filipino, Finnish, French, German, Greek, Hindi, Indonesian, Italian, Japanese, Korean, Malay, Polish, Portuguese, Romanian, Russian, Slovak, Spanish, Swedish, Tamil, Turkish and Ukrainian. For Flash v2.5 you get 32 languages (with Hungarian, Norwegian and Vietnamese added). For Eleven v3 you get a full 74 languages. Adding Afrikaans, Armenian, Assamese, Azerbaijani, Belarusian, Bengali, Bosnian, Catalan, Cebuano, Chichewa, Estonian, Galician, Georgian, Gujarati, Hausa, Hebrew, Icelandic, Irish, Javanese, Kannada, Kazakh, Kirghiz (Kyrgyz), Latvian, Lingala, Lithuanian, Luxembourgish, Malayalam, Marathi, Nepali, Pashto, Persian, Punjabi, Sindhi, Somali, Swahili, Telugu, Thai, Urdu and Welsh.', 'Text-to-Speech (TTS) for accessibility and audio reporting.', 6, 3, 5, '2026-05-14 23:35:39.493612+02', '2026-05-14 23:41:54.985827+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('c32e57b4-8023-4764-aac5-47c38ebf882c', 'google-colab', 'Google Colab', 'https://replit.com', 'Building Your Own Tools', '["Building Your Own Tools"]', 'Cloud-hosted Jupyter Notebook environment for running Python and data analysis code. Google Colab is a hosted Jupyter Notebook service that provides free access to computing resources, including GPUs (Graphics Processing Units) and TPUs (Tensor Processing Units). Colab allows researchers to write and execute Python code in the browser. Colab has lowered the barrier to entry for AI research globally. It is the "playground" where much of the open-source AI revolution is tested and shared. No setup. Standard for sharing reproducible research. However, runtime disconnects when you close the browser (so you can’t use this for long production jobs) and it has privacy issues (code runs on Google servers).', 'Data Science & Visualization "Vibes."', 0, 3, 5, '2026-05-14 23:35:39.521839+02', '2026-05-14 23:41:54.987524+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('82061684-2120-4e4b-92a4-b0449a783dab', 'google-pinpoint', 'Google Pinpoint', 'https://journaliststudio.google.com/pinpoint', 'Verification & Investigations', '["Verification & Investigations"]', 'Document analysis tool for journalists that makes large collections of PDFs, images, and audio searchable. Google Pinpoint is a research tool specifically engineered for investigative journalists and academics dealing with massive document dumps. It uses Google''s OCR (Optical Character Recognition) 42 and speech-to-text technologies to make thousands of PDFs, images, handwritten notes, and audio files searchable. Pinpoint’s strength lies in its ability to handle "unstructured" data. It can transcribe audio files ocuments and automatically index them alongside PDF text. A key feature is entity extraction 43. It automatically identifies and highlights people, organizations, and locations across the entire dataset, revealing connections that a human reader might miss. As part of the "Google News Initiative 44" Pinpoint is free for journalists, reflecting Google''s strategy to integrate itself into the news gathering ecosystem 45. While powerful, this provenance is a double-edged sword. Using Pinpoint means uploading potentially sensitive investigative material to Google''s servers. While Google promises privacy "by default," the threat model of an investigation targeting Google partners or government entities might preclude its use.', 'Investigative document analysis (OCR & Entity Extraction).', 0, 3, 6, '2026-05-14 23:35:39.523016+02', '2026-05-14 23:41:54.988174+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('cab5dc82-51ec-4e41-a95d-7a8013ec95b3', 'invid-weverify', 'InVID / WeVerify', 'https://gijn.org/stories/making-video-audio-files-searchable/#:~:text=Drive%29', 'Verification & Investigations', '["Verification & Investigations"]', 'Browser-based video and image verification toolkit for social media and conflict reporting. The InVID/WeVerify plugin is a browser extension designed to help journalists 47 and fact- checkers verify videos and images from social media platforms like Facebook, YouTube and X. The tool offers a suite of forensic modules. It can fragment a video into keyframes, allowing users to perform reverse image searches on specific moments to find the original source. It includes metadata readers, optical character recognition (OCR) for text within images, and pinpoint/#:~:text=Initiative%20newsinitiative,its%20new%20functionality%20%27Structured techniques-to-increase-efficiency-in-the- newsroom/#:~:text=,complex%20ideas%20and%20generate%20connections plugin/#:~:text=This%20toolkit%20is%20provided%20by,when%20verifying%20videos%20and%20image s forensic filters (like magnifying lens and error level analysis) to detect image manipulation. Recent updates added 48 a "CheckGIF" tool to compare manipulated images against originals and a "Database of Known Fakes". It is comprehensive, free, and trusted by major newsrooms, consolidating multiple forensic tools into one interface. However, it relies on third-party APIs 49 (like Twitter/YouTube) which can break or change access rules, disrupting workflows. ● The tool''s purpose: Video forensics and keyframe extraction. ● Relevance to journalism: This is the standard EU-funded tool for verifying footage from conflict zones. It is essential for checking "reverse image search" across Yandex, Baidu, and Google simultaneously.', NULL, 0, 5, 1, '2026-05-14 23:35:39.525755+02', '2026-05-14 23:41:54.989128+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('1201f842-696c-46aa-a0a9-21aa4badb359', 'neo4j', 'Neo4j', 'https://aleph.occrp.org', 'Verification & Investigations', '["Verification & Investigations"]', 'Graph database used to model and analyse complex networks such as financial flows or social relationships. platform-aleph- pro#:~:text=Created%20by%20OCCRP%20nearly%2010,collaborate%20on%20vast%20data%20investi gations investigative-data- platform#:~:text=OCCRP%20www,journalists%2C%20researchers%2C%20and%20the%20public Neo4j is the world''s leading graph database management system 61. Unlike traditional relational databases (SQL) that store data in tables, Neo4j stores data as "nodes" and "relationships." This makes it the ultimate tool for mapping complex networks, such as money laundering schemes, social media interactions, or cyber infrastructure.', 'Network mapping and relationship analysis.', 3, 8, 0, '2026-05-14 23:35:39.529329+02', '2026-05-14 23:41:54.992177+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('12b9be51-d897-42d6-b53c-6968fe621c8a', 'openstreetmap', 'OpenStreetMap', 'https://dangerzone.rocks', 'Verification & Investigations', '["Verification & Investigations"]', 'Open geographic database and query interface for extracting detailed mapping data. OpenStreetMap is a website where volunteers around the world add and update information about roads, buildings, paths, villages, and landmarks. Think of it as a shared public map that anyone can improve and anyone can use. While Google Maps is mainly about directions, traffic, and businesses. OpenStreetMap is about recording what actually exists in a place. Because it is community-driven, it often shows things Google Maps misses, especially in rural areas, poorer regions, or conflict zones. OpenStreetMap often records things like footpaths, dirt roads, and informal routes that people actually use, but that are not “official”. Small or non-commercial buildings such as clinics, water points, refugee camps, schools, mosques, or community halls that have no business listings. For journalists, OpenStreetMap is useful when reporting on places that are under-mapped or ignored, because it can show whether basic infrastructure exists even when there are no reviews, photos, or commercial listings.', 'Open geospatial investigation and mapping.', 0, 6, 0, '2026-05-14 23:35:39.531982+02', '2026-05-14 23:41:54.996667+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('b4782153-b585-4420-965e-e1eb5e748857', 'pandas', 'Pandas', NULL, 'Writing & Analysis', '["Writing & Analysis"]', 'Python library for data analysis, manipulation, and statistical computation. Pandas is the top alternative to Excel and OpenRefine for serious data analysis. It is an open- source Python library that provides high-performance, easy-to-use data structures and analysis tools. Pandas is better than Excel when data becomes large, complex, or needs to be handled responsibly. Excel is a visual spreadsheet designed for manual work, while Pandas is a data analysis engine built for scale and repeatability. With Pandas, every step of cleaning, filtering, or analysing data is written as code, which means the process is transparent, reusable, and auditable, a critical requirement for serious journalism. Pandas can handle millions of rows where Excel and OpenRefine often fail, and because it runs locally, journalists retain full control over their data.', 'Sovereign large-scale data analysis.', 0, 7, 0, '2026-05-14 23:35:39.533235+02', '2026-05-14 23:41:54.99792+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('caa12f18-9136-4f54-ac84-9c11177a84da', 'tor-browser', 'Tor Browser', NULL, 'Security Challenges', '["Security Challenges"]', 'Privacy-focused browser that anonymizes internet traffic via the Tor network. Tor Browser is a modified Firefox browser that routes your internet traffic through the Tor network, which is a decentralized system of volunteer-run servers. It encrypts and bounces your communications through multiple nodes, making it very difficult for anyone to trace your browsing or messaging back to you. This allows journalists to anonymize their web activity and access sites that may be censored or blocked on local networks. For journalists, Tor is invaluable for protecting the confidentiality of online research and communications. It enables reaching information on the “open” or dark web anonymously – for example, accessing whistleblower platforms or publishing outlets via their .onion (Tor-only) sites. It helps keep browsing habits and source communications hidden from government surveillance or ISP tracking, which is crucial in investigative reporting and in authoritarian regimes.', 'Anonymous research and censorship-resistant web access.', 0, 4, 2, '2026-05-14 23:35:39.537571+02', '2026-05-14 23:41:54.999862+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('a7a342f6-8c85-412b-aeb7-cf90b0e7b4b7', 'visualping', 'Visualping', 'https://weverify.eu/verification-', 'Verification & Investigations', '["Verification & Investigations"]', 'Website monitoring service that alerts users when visual or textual changes occur on web pages. Visualping is a simple yet potent website change detection tool 52. It monitors web pages for visual or text changes and sends alerts via email, Slack, or SMS. It is widely used for competitive intelligence, regulatory monitoring, and tracking disparate digital footprints that do not offer RSS feeds or APIs.', 'Monitoring changes on government websites.', 4, 2, 2, '2026-05-14 23:35:39.539913+02', '2026-05-14 23:41:55.002897+02') ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.tools (id, slug, name, url, primary_category, categories, description, purpose, cdi_cost, cdi_difficulty, cdi_invasiveness, created_at, updated_at) VALUES ('f4f98b27-c732-46cc-abff-b6145881a897', 'wordtune', 'Wordtune', 'https://techcrunch.com/2025/08/04/perplexity-accused-of-scraping-websites-that-explicitly-blocked-ai-', 'Writing & Analysis', '["Writing & Analysis"]', 'Writing assistant that rewrites sentences to adjust tone, clarity, and emphasis. Wordtune is an AI-powered writing companion focused on phrasing and tone. Unlike a grammar checker, it rewrites sentences to be more casual, formal, concise, or expanded, acting as a "co-writer" rather than a proofreader. Excellent for overcoming writer''s block or refining non-native English. The tool''s purpose: To help journalists quickly improve sentence clarity, tone, and flow without changing the underlying meaning of their reporting. scraping/#:~:text=AI%20startup%20Perplexity%20is%20crawling,to%20internet%20infrastructure%20pro vider%20Cloudflare standard-scrape-publisher-sites-licensing-2024-06- 21/#:~:text=Exclusive%3A%20Multiple%20AI%20companies%20bypassing,scraping%20of%20their%20c ontent Relevance to journalism: Particularly useful for journalists writing in a second language or under deadline pressure, Wordtune helps refine copy while keeping editorial control with the reporter, not the tool.', NULL, 4, 1, 3, '2026-05-14 23:35:39.540489+02', '2026-05-14 23:41:55.003201+02') ON CONFLICT (slug) DO NOTHING;
